let characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
let result = '';
let length = 48; // Desired length of the random string
for (let i = 0; i < length; i++) {
  result += characters.charAt(Math.floor(Math.random() * characters.length));
}
return { randomString: result };

parameters.text:
=## Latest Message

{{ $('Log New Message to Sheet').item.json['Message Content'] }}

## Message Context

{{ $('Log New Message to Sheet').item.json['Previous Interactions (Aggregated)'] }}

Output Format: Format your response in Markdown. Use \n\n to separate paragraphs. Use standard Markdown syntax for emphasis (**bold**, *italic*) or links ([text](url)) where appropriate. Do not use any HTML tags whatsoever (no <p>, <br>, <strong>, <em>, etc.). The response must be pure Markdown.

parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "escalate_to_instructor": {
      "type": "boolean",
      "description": "True if the message requires instructor attention, false if AI can handle it"
    },
    "escalation_reason": {
      "type": "string",
      "enum": [
        "sales_opportunity",
        "personal_question",
        "coaching_request",
        "payment_or_refund",
        "content_change_request",
        "complaint_or_dispute",
        "contact_request",
        "unknown_instructor_info",
        "sensitive_disclosure",
        "ambiguous_message",
        "not_applicable"
      ],
      "description": "Reason for escalation. Use 'not_applicable' when escalate_to_instructor is false. 'sales_opportunity' takes priority."
    },
    "response": {
      "type": "string",
      "description": "The AI-generated response to send to the student, formatted in pure Markdown only. Must not contain any HTML tags (no <p>, <br>, <strong>, <em>, etc.). Use \\n\\n for paragraph breaks and standard Markdown syntax for emphasis or links. Empty string if escalated to instructor."
    },
    "confidence": {
      "type": "string",
      "enum": ["high", "medium", "low"],
      "description": "Confidence level in the response or escalation decision"
    },
    "tools_used": {
      "type": "array",
      "items": {
        "type": "string",
        "enum": ["jina_search", "none"]
      },
      "description": "Which tools were used to formulate the response"
    }
  },
  "required": ["escalate_to_instructor", "escalation_reason", "response", "confidence", "tools_used"]
}

